package ui.student;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import dao.*;import model.*;import util.*;import ui.common.TableStyle;
public class RecommendationsPanel extends JPanel{ JTable table=new JTable(); public RecommendationsPanel(){ setBackground(UITheme.BG); setLayout(new BorderLayout()); add(UITheme.title("AI-Based Recommendations"),BorderLayout.NORTH); add(new JScrollPane(table),BorderLayout.CENTER); load(); } void load(){ Student s=new StudentDAO().getByUserId(Session.getUserId()); DefaultTableModel m=new DefaultTableModel(new Object[]{"ID","Title","Field","City","Type","Stipend"},0); if(s!=null) for(Internship j:new RecommendationController().recommend(s))m.addRow(new Object[]{j.getId(),j.getTitle(),j.getField(),j.getCity(),j.getType(),j.getStipend()}); table.setModel(m); TableStyle.apply(table);} }
